#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double T1, T2, t1, t2;
        scanf("%lf %lf %lf %lf", &T1, &T2, &t1, &t2);
        double area = (T1 + t2) * (T2 + t1) - (T1 * T2) - (T1 + t2 > T2 + t1 ? (T1 + t2 - T2 - t1) * (T1 + t2 - T2 - t1) / 2 : 0) - (T2 + t1 > T1 + t2 ? (T2 + t1 - T1 - t2) * (T2 + t1 - T1 - t2) / 2 : 0);
        double probability = area / ((T1 + T2) * (T1 + T2));
        printf("%.6f\n", probability);
    }
    return 0;
}

