const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [T1, T2, t1, t2] = readline().split(' ').map(Number);
    let area = (T1 + t2) * (T2 + t1) - (T1 * T2);
    if (T1 + t2 > T2 + t1) area -= (T1 + t2 - T2 - t1) * (T1 + t2 - T2 - t1) / 2;
    if (T2 + t1 > T1 + t2) area -= (T2 + t1 - T1 - t2) * (T2 + t1 - T1 - t2) / 2;
    const probability = area / ((T1 + T2) * (T1 + T2));
    console.log(probability.toFixed(6));
}
